    {
      "keystrokes": "cat > /app/apply_macros.vim <<'EOF'\ncall setreg('a', \":s/\\\\s\\\\+//g\\\\<CR>\")\ncall setreg('b', \":s/^\\\\([^,]*\\\\),\\\\([^,]*\\\\),\\\\([^,;]*\\\\)/\\\\3;\\\\2;\\\\1/\\\\<CR>\")\ncall setreg('c', \":s/;OK$//\\\\<CR>gUU$A;OK\\\\<Esc>\")\n:%normal! @a\n:%normal! @b\n:%normal! @c\n:wq\nEOF\n",
      "duration": 0.3
    },
    {
      "keystrokes": "vim -Nu NONE -n -Es /app/input.csv -S /app/apply_macros.vim\n",
